section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/css-in-js-advanced.json",
  "title": "CSS-in-JS Advanced",
  "type": "object",
  "required": [
    "artefact_id",
    "library_choice",
    "rationale",
    "ssr_extraction",
    "runtime_cost_kb",
    "theme_strategy",
    "rsc_compatibility",
    "owner",
    "last_touched",
    "template_version",
    "status"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "library_choice": {
      "type": "string",
      "description": "styled-components | emotion | linaria | vanilla-extract | panda | stitches | none"
    },
    "rationale": {
      "type": "string",
      "minLength": 1
    },
    "ssr_extraction": {
      "type": "string",
      "description": "how SSR critical CSS is extracted"
    },
    "runtime_cost_kb": {
      "type": "number",
      "description": "minified+gzipped runtime cost in kB"
    },
    "theme_strategy": {
      "type": "string",
      "description": "css-vars-runtime | build-time-variants | jsx-prop"
    },
    "rsc_compatibility": {
      "type": "string",
      "description": "compatible | client-boundary-required | incompatible"
    }
  },
  "additionalProperties": false
}
